from fastapi import FastAPI, HTTPException, Depends, Security
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials, OAuth2PasswordBearer
from pydantic import BaseModel, EmailStr
from datetime import datetime, timedelta
from typing import Optional
import jwt
import hashlib
import secrets

app = FastAPI(title="Authentication API", version="1.0.0")

# ── Configuration ───────────────────────────────────────
SECRET_KEY = "your-secret-key-change-in-production"
ALGORITHM = "HS256"
ACCESS_TOKEN_EXPIRE_MINUTES = 30
REFRESH_TOKEN_EXPIRE_DAYS = 7

# ── Models ──────────────────────────────────────────────
class UserLogin(BaseModel):
    email: EmailStr
    password: str


class TokenResponse(BaseModel):
    access_token: str
    refresh_token: str
    token_type: str = "bearer"
    expires_in: int


class TokenRefresh(BaseModel):
    refresh_token: str


# ── In-memory storage ──────────────────────────────────
users_db = {}
refresh_tokens_db = {}
api_keys_db = {}


# ── Helper functions ────────────────────────────────────
def hash_password(password: str) -> str:
    return hashlib.sha256(password.encode()).hexdigest()


def create_access_token(user_id: str, role: str) -> str:
    payload = {
        "sub": user_id,
        "role": role,
        "exp": datetime.utcnow() + timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES),
        "iat": datetime.utcnow(),
        "type": "access"
    }
    return jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)


def create_refresh_token(user_id: str) -> str:
    payload = {
        "sub": user_id,
        "exp": datetime.utcnow() + timedelta(days=REFRESH_TOKEN_EXPIRE_DAYS),
        "iat": datetime.utcnow(),
        "type": "refresh",
        "jti": secrets.token_hex(16)
    }
    token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    refresh_tokens_db[token] = {"user_id": user_id, "used": False}
    return token


# ── Dependencies ─────────────────────────────────────────
security = HTTPBearer()
oauth2_scheme = OAuth2PasswordBearer(tokenUrl="auth/login")


async def get_current_user(
    credentials: HTTPAuthorizationCredentials = Security(security)
) -> dict:
    try:
        payload = jwt.decode(credentials.credentials, SECRET_KEY, algorithms=[ALGORITHM])
        if payload.get("type") != "access":
            raise HTTPException(status_code=401, detail="Invalid token type")
        user_id = payload.get("sub")
        if user_id not in users_db:
            raise HTTPException(status_code=401, detail="User not found")
        return {"user_id": user_id, **users_db[user_id]}
    except jwt.ExpiredSignatureError:
        raise HTTPException(status_code=401, detail="Token expired")
    except jwt.InvalidTokenError:
        raise HTTPException(status_code=401, detail="Invalid token")


# ── API Key authentication ──────────────────────────────
async def verify_api_key(api_key: str = Security(HTTPBearer())):
    if api_key.credentials not in api_keys_db:
        raise HTTPException(status_code=401, detail="Invalid API key")
    return api_keys_db[api_key.credentials]


# ── Auth endpoints ──────────────────────────────────────
@app.post("/auth/register", status_code=201)
async def register(user: UserLogin):
    if user.email in users_db:
        raise HTTPException(status_code=400, detail="Email already registered")
    users_db[user.email] = {
        "password": hash_password(user.password),
        "role": "user"
    }
    return {"message": "User registered successfully"}


@app.post("/auth/login", response_model=TokenResponse)
async def login(user: UserLogin):
    stored = users_db.get(user.email)
    if not stored or stored["password"] != hash_password(user.password):
        raise HTTPException(status_code=401, detail="Invalid credentials")
    access_token = create_access_token(user.email, stored["role"])
    refresh_token = create_refresh_token(user.email)
    return TokenResponse(
        access_token=access_token,
        refresh_token=refresh_token,
        expires_in=ACCESS_TOKEN_EXPIRE_MINUTES * 60
    )


@app.post("/auth/refresh", response_model=TokenResponse)
async def refresh_token(data: TokenRefresh):
    stored = refresh_tokens_db.get(data.refresh_token)
    if not stored or stored["used"]:
        raise HTTPException(status_code=401, detail="Invalid refresh token")
    stored["used"] = True
    user_id = stored["user_id"]
    access_token = create_access_token(user_id, users_db[user_id]["role"])
    new_refresh_token = create_refresh_token(user_id)
    return TokenResponse(
        access_token=access_token,
        refresh_token=new_refresh_token,
        expires_in=ACCESS_TOKEN_EXPIRE_MINUTES * 60
    )


@app.post("/api-keys")
async def create_api_key(current_user: dict = Depends(get_current_user)):
    api_key = f"ak_{secrets.token_hex(32)}"
    api_keys_db[api_key] = {"user_id": current_user["user_id"]}
    return {"api_key": api_key, "message": "Store this key securely"}


@app.get("/protected")
async def protected_route(current_user: dict = Depends(get_current_user)):
    return {"message": f"Hello {current_user['user_id']}", "role": current_user["role"]}
